#!/usr/bin/env python3
import numpy as np
import pandas as pd
from mtf_data import get_htf_data, align_htf_to_ltf

# Hypothesis: 4h Bollinger Band squeeze breakout with 1d trend filter and volume confirmation.
# Long when Bollinger Bands squeeze (low volatility) breaks upward with bullish 1d trend and volume spike.
# Short when Bollinger Bands squeeze breaks downward with bearish 1d trend and volume spike.
# Exit when price returns to middle Bollinger Band (mean reversion).
# Uses Bollinger Band width percentile to detect squeeze (<20th percentile) and breakout (>80th percentile).
# Target: 20-40 trades/year to minimize fee drag while capturing volatility expansion moves.

def generate_signals(prices):
    n = len(prices)
    if n < 60:
        return np.zeros(n)
    
    high = prices['high'].values
    low = prices['low'].values
    close = prices['close'].values
    volume = prices['volume'].values
    
    # Get 1d data for EMA50 trend filter
    df_1d = get_htf_data(prices, '1d')
    if len(df_1d) < 2:
        return np.zeros(n)
    
    close_1d = df_1d['close'].values
    
    # 1-day EMA50 for trend filter
    ema50_1d = pd.Series(close_1d).ewm(span=50, adjust=False, min_periods=50).mean().values
    ema50_1d_aligned = align_htf_to_ltf(prices, df_1d, ema50_1d)
    
    # Bollinger Bands on 4h timeframe (20-period, 2 std dev)
    bb_period = 20
    bb_std = 2
    sma_bb = pd.Series(close).rolling(window=bb_period, min_periods=bb_period).mean().values
    bb_std_dev = pd.Series(close).rolling(window=bb_period, min_periods=bb_period).std().values
    upper_bb = sma_bb + (bb_std_dev * bb_std)
    lower_bb = sma_bb - (bb_std_dev * bb_std)
    middle_bb = sma_bb
    
    # Bollinger Band Width (BBW) for squeeze detection
    bb_width = (upper_bb - lower_bb) / middle_bb
    
    # BBW percentile (20-period lookback) to identify squeeze (<20th percentile) and expansion (>80th percentile)
    bb_width_series = pd.Series(bb_width)
    bb_width_percentile = bb_width_series.rolling(window=50, min_periods=20).apply(
        lambda x: pd.Series(x).rank(pct=True).iloc[-1] * 100, raw=False
    ).values
    
    # Squeeze condition: BBW < 20th percentile (low volatility)
    squeeze_condition = bb_width_percentile < 20
    
    # Breakout condition: BBW > 80th percentile (high volatility expansion)
    breakout_condition = bb_width_percentile > 80
    
    # Volume filter: volume > 1.5x 20-period average
    vol_ma = pd.Series(volume).rolling(window=20, min_periods=20).mean().values
    volume_filter = volume > (vol_ma * 1.5)
    
    signals = np.zeros(n)
    position = 0  # 0: flat, 1: long, -1: short
    
    # Start after warmup period
    start_idx = 50
    
    for i in range(start_idx, n):
        # Skip if any required data is NaN
        if (np.isnan(ema50_1d_aligned[i]) or np.isnan(upper_bb[i]) or 
            np.isnan(lower_bb[i]) or np.isnan(middle_bb[i]) or 
            np.isnan(vol_ma[i]) or np.isnan(bb_width_percentile[i])):
            signals[i] = 0.0
            continue
        
        # Long condition: BB breakout above upper BB, bullish 1d trend, volume spike, after squeeze
        if (breakout_condition[i] and 
            close[i] > upper_bb[i] and 
            close[i] > ema50_1d_aligned[i] and 
            volume_filter[i] and
            squeeze_condition[i-1]):  # Was in squeeze before breakout
            signals[i] = 0.25
            position = 1
        # Short condition: BB breakout below lower BB, bearish 1d trend, volume spike, after squeeze
        elif (breakout_condition[i] and 
              close[i] < lower_bb[i] and 
              close[i] < ema50_1d_aligned[i] and 
              volume_filter[i] and
              squeeze_condition[i-1]):  # Was in squeeze before breakout
            signals[i] = -0.25
            position = -1
        # Exit conditions: price returns to middle BB (mean reversion)
        elif position == 1 and close[i] < middle_bb[i]:
            signals[i] = 0.0
            position = 0
        elif position == -1 and close[i] > middle_bb[i]:
            signals[i] = 0.0
            position = 0
        # Hold position
        else:
            if position == 1:
                signals[i] = 0.25
            elif position == -1:
                signals[i] = -0.25
            else:
                signals[i] = 0.0
    
    return signals

